// Staff Development Programme — session data (verbatim from original handbook)
const createDebrief = () => ({ name: 'Weekly Debrief & Celebration', desc: 'Reflect on one positive moment from the week and one scenario to deconstruct with a solution-focused approach. Appreciate a colleague\'s contribution and celebrate a student\'s success.' });

const sessionData = [
    { week: 1, term: 1, title: 'Regulating the Body', focus: 'Foundations', theme: 'Regulation', objectives: ['Understand the link between physical sensations and emotional state.', 'Introduce the Neurosequential Model\'s concept of "Regulate, Relate, Reason."', 'Learn and practice simple, effective regulation techniques.'], activities: [createDebrief(), {name: 'Somatic Grounding: Feet on the Floor', desc: 'A guided practice focusing on the physical sensation of feet on the ground to anchor in the present moment and notice the body\'s state.'}, {name: 'The 4-7-8 Breath', desc: 'Practitioner leads the group in several rounds of this calming breathing technique, explaining the physiological effect of a longer exhale on the nervous system.'}, {name: 'Rhythmic Regulation', desc: 'Engage in a simple, rhythmic activity like bilateral tapping (crossing arms and tapping shoulders) while listening to calming music to soothe the brainstem.'}, {name: '"My Safe Place" Visualization', desc: 'A guided imagery exercise where participants visualize a safe, calming place, focusing on sensory details they can mentally retreat to during stress.'}], resources: 'Flip chart/whiteboard, pens.', notes: 'Emphasise that this is a non-judgmental space. Normalise feelings of stress and overwhelm. The goal is to build awareness, not to force calmness.', videoLink: 'https://www.youtube.com/embed/cEqZthCaMpo' },
    { week: 2, term: 1, title: 'Thinking Patterns', focus: 'Foundations', theme: 'TA', objectives: ['Identify common unhelpful thinking patterns ("thinking traps").', 'Introduce the TA concept of the "Adult" ego state as the voice of reason.', 'Practice challenging and reframing a negative thought.'], activities: [createDebrief(), {name: 'Ego State Introduction', desc: 'Introduce Parent, Adult, and Child ego states using simple diagrams. Participants share examples of when they\'ve experienced each state.'}, {name: 'Identifying Thinking Traps', desc: 'Using a handout, the group identifies cognitive distortions (e.g., catastrophizing) in provided work-based scenarios.'}, {name: 'Challenging Thoughts in Dyads', desc: 'In pairs, one person shares an unhelpful thought while the other helps them challenge it from a curious, "Adult" ego state perspective.'}, {name: 'STOPP Technique Practice', desc: 'Introduce the STOPP (Stop, Take a breath, Observe, Pull back/Perspective, Proceed) technique as a practical tool for managing reactive thoughts.'}], resources: '"Thinking Traps" handout.', notes: 'This can be challenging. Reassure the group that we all have these thought patterns. The goal is awareness, not perfection.' , videoLink: 'https://www.youtube.com/embed/jsyuxEntsas' },
    { week: 3, term: 1, title: 'Behavioural Strategies', focus: 'Foundations', theme: 'Regulation', objectives: ['Connect thoughts and feelings to behavioural responses.', 'Develop a personalised toolkit of self-regulation strategies.', 'Role-play using a strategy in a difficult scenario.'], activities: [createDebrief(), {name: '"My Triggers" Personal Reflection', desc: 'Private journaling on what situations or feelings lead to reactive behaviour, without judgment.'}, {name: 'Personal Regulation Toolkit Creation', desc: 'Brainstorm and list personal, practical strategies (sensory, movement, social) that can be used in under 2 minutes at work.'}, {name: '"Pause and Plan" Role-Play', desc: 'Role-play a triggering scenario, focusing on using a toolkit strategy before responding. Debrief the experience.'}, {name: 'Commitment to Action', desc: 'Each person shares one regulation strategy they will consciously try to use this week.'}], resources: 'Paper, pens, Regulation Toolkit worksheet.', notes: 'Keep the role-plays short and focused on the process of using a strategy, not on "solving" the scenario.' , videoLink: 'https://www.youtube.com/embed/56c1uL_O8Jk' },
    { week: 4, term: 1, title: 'Transactional Analysis Intro', focus: 'Foundations', theme: 'TA', objectives: ['Introduce basic TA transactions (Complementary vs. Crossed).', 'Explore the concept of professional boundaries.', 'Practice assertive communication.'], activities: [createDebrief(), {name: 'Transaction Spotting', desc: 'In pairs, analyze a provided work-based scenario (e.g., an email exchange) and diagram the transactions to identify if they are Complementary or Crossed.'}, {name: 'Mapping Support Networks', desc: 'Individually, participants map out their personal and professional support systems, identifying who they go to for different types of support.'}, {name: 'Boundary Setting Scripts', desc: 'Participants work individually to write down pre-prepared phrases for gracefully setting boundaries in different situations.'}, {name: 'Assertive "No" Practice', desc: 'In a group go-around, practice saying "no" to small, low-stakes requests to build comfort with the skill.'}], resources: 'Flip chart/whiteboard, pens, scenario handouts.', notes: 'Frame "saying no" as a pro-social skill that protects relationships and prevents burnout, rather than as a negative or selfish act.' , videoLink: 'https://www.youtube.com/embed/oPJtRDul0do' },
    { week: 5, term: 1, title: 'Self-Worth & Goals', focus: 'Foundations', theme: 'TA', objectives: ['Introduce the TA concept of "Strokes" (units of recognition).', 'Practice self-affirmation and recognising personal strengths.', 'Set a small, achievable well-being goal.'], activities: [createDebrief(), {name: 'The "Stroke" Exchange', desc: 'A structured group activity where each person gives a specific, positive, unconditional "stroke" (affirmation) to the person on their right.'}, {name: '"I Am Good At..." Circle', desc: 'Each person completes the sentence "One thing I\'m good at is..." to practice self-affirmation in a supportive group setting.'}, {name: 'Goal Setting: Tiny Habits', desc: 'Introduce the "Tiny Habits" model to set one small, achievable well-being goal for the week (e.g., "After I hang up my coat, I will take three deep breaths.").'}, {name: 'Values-Based Goal Alignment', desc: 'Participants reflect on a core personal value and check if their tiny habit aligns with that value, increasing motivation.'}], resources: 'Paper, pens.', notes: 'Many people find self-affirmation difficult. Acknowledge this and encourage participants to start small.' , videoLink: 'https://www.youtube.com/embed/jyxKxAlkuDE' },
    { week: 6, term: 1, title: 'Debrief: Regulating the Body', focus: 'Application', theme: 'Regulation', objectives: ['To embed the learning from week 1.', 'To practice using regulation models as a live debriefing tool.', 'To build psychological safety within the group.'], activities: [createDebrief(), {name: 'Somatic Storytelling', desc: 'A volunteer shares a stressful event while the group listens for the physical/somatic language used (e.g., "my stomach dropped").'}, {name: 'Co-regulation in Practice', desc: 'The group collectively uses a calming technique (e.g., 4-7-8 breath) together after hearing the story, demonstrating co-regulation.'}, {name: 'Strategy Brainstorm', desc: 'For the deconstructed scenario, the group brainstorms 2-3 regulation strategies that could have been used in the moment.'}, {name: 'Reflection on Parallel Process', desc: 'Discuss if the feelings activated in the group while listening mirrored the feelings in the story, and how this happens with students.'}], resources: 'Flip chart/whiteboard, pens.', notes: 'The goal is analysis and shared learning, not problem-solving. Keep the focus on the process, not the content of the story.' , videoLink: 'https://www.youtube.com/embed/qxyVCjp48S4' },
    { week: 7, term: 1, title: 'Debrief: Behavioural Strategies', focus: 'Application', theme: 'Regulation', objectives: ['To embed the learning from week 3.', 'To practice using behavioural models as a live debriefing tool.', 'To build psychological safety within the group.'], activities: [createDebrief(), {name: 'Action-Impulse Separation', desc: 'In the deconstructed scenario, identify the difference between the *impulse* (what the person felt like doing) and the *action* (what they actually did).'}, {name: 'Toolkit Application', desc: 'Discuss which specific strategy from a personal regulation toolkit could have been used to manage the impulse before acting.'}, {name: 'Chain Analysis', desc: 'Map out the chain of events: Trigger -> Thought -> Feeling -> Behaviour -> Consequence. Identify where a different action could have changed the outcome.'}, {name: 'Role-Play the Alternative', desc: 'Two volunteers role-play the alternative ending to the scenario, where a regulation strategy is used effectively.'}], resources: 'Whiteboard, pens.', notes: 'Focus on exploring choices and strategies rather than judging past actions. The tone should be curious and forward-looking.' , videoLink: 'https://www.youtube.com/embed/rpJYACy8ZoI' },
    { week: 8, term: 1, title: 'Staying Steady in the Moment', focus: 'MHFA', theme: 'MHFA', objectives: ['Understand that your own regulation is the first tool in any acute moment — you cannot co-regulate another person from a dysregulated place.', 'Learn simple, in-the-moment ways to help someone settle from acute distress, panic, or upset.', 'Know how to receive a difficult disclosure calmly and safely, holding the moment without taking it on.'], activities: [createDebrief(), {name: 'Regulate Before You Relate', desc: 'Revisit the "Regulate, Relate, Reason" sequence from Week 1, this time pointed outward: a 30-second personal grounding routine to run *before* you step in to help, so you arrive steady.'}, {name: 'Settling Acute Distress', desc: 'In trios (helper, person in distress, observer), practise a calm, low-stimulus response to someone who is panicking or overwhelmed — soft voice, slower pace, offering choice and space rather than fixing.'}, {name: 'Receiving a Disclosure', desc: 'Practise the first 60 seconds after someone shares something heavy: stay calm, thank them for trusting you, avoid promising secrecy, and gently hold the moment. Debrief how it felt to receive rather than solve.'}, {name: 'After the Moment', desc: 'Discuss the "decompression" you need once an acute moment passes — and the golden thread idea from Week 9: holding someone\'s breaks steadily is itself the gold, even when nothing is "fixed".'}], resources: 'Quiet space, grounding-routine prompt cards, the school\'s safeguarding/disclosure procedure to hand.', notes: 'High emotional labour lives here — name that openly. This session is about confidence to stay present, not clinical intervention; always route any safeguarding concern through the proper channels. Reassure the group that "steady and kind" is enough; they do not have to have the answers.' , videoLink: 'https://www.youtube.com/embed/1Evwgu369Jw' },
    { week: 9, term: 1, title: 'Kintsugi: The Golden Thread', focus: 'Philosophy', theme: 'Integration', objectives: ['Understand the Kintsugi philosophy — the Japanese art of repairing broken pottery with gold, so the mended piece is more beautiful for having survived the breaks.', 'See yourself as the "golden thread": the practitioner who holds and rejoins the pieces rather than hiding the cracks.', 'Set this image as a touchstone for the year ahead — a lens we will return to in the sessions that follow.'], activities: [createDebrief(), {name: 'The Kintsugi Story', desc: 'Introduce the Japanese art of repairing broken pottery with gold. Sit with the central idea from the Inclusion Base philosophy: young people are not of less value for being broken — they are more beautiful for having survived the breaks.'}, {name: 'Spotting the Gold', desc: 'In pairs, each person recalls a young person whose "breaks" they have helped hold. Name the specific golden thread — the relational act — that began to rejoin the pieces.'}, {name: 'The Practitioner as Golden Thread', desc: 'Discuss how staff carry the gold: regulation, relationship and quiet consistency are what make a repair valuable, and what make the process more worthwhile for having happened. Notice how this thread will run through every theme in the year ahead.'}, {name: 'A Touchstone to Keep', desc: 'Each person names one "crack" they have already turned to gold — a challenge they survived and the strength it left behind — and writes it down to revisit as the programme unfolds.'}], resources: 'A piece of kintsugi pottery or images of it; gold pens and paper.', notes: 'Placed early on purpose: this is the philosophical touchstone for the whole programme. Hold it gently and personally — it honours both the young people and the staff who do this demanding, valuable work. Connect it explicitly to the Inclusion Base philosophy: we take responsibility for the students we have, not those we\'d like to have. We will return to the golden thread throughout the year.' , videoLink: 'https://www.youtube.com/embed/TQW8t6w0Cy4' },
    { week: 10, term: 1, title: 'Recognising Distress', focus: 'MHFA', theme: 'MHFA', objectives: ['Introduce the purpose and limits of the MHFA role.', 'Learn to notice behavioural, physical, and emotional signs of distress in others.'], activities: [createDebrief(), {name: 'Case Study Analysis', desc: 'In small groups, read short, anonymous case studies and highlight the behavioural, physical, and emotional signs of distress.'}, {name: '"Noticing Patterns" Discussion', desc: 'A group discussion about the difference between a one-off "bad day" and a consistent pattern of behaviour that might indicate distress.'}, {name: 'Circles of Responsibility', desc: 'Draw two circles: "My Role" and "Not My Role." Group members place sticky notes with actions (e.g., "Listen," "Diagnose," "Advise," "Signpost") in the correct circle.'}, {name: 'Empathetic Opening Lines', desc: 'Brainstorm and practice gentle, non-intrusive ways to start a conversation, such as "I\'ve noticed... and I just wanted to check in."'}], resources: 'Case study handouts, sticky notes, pens.', notes: 'Emphasise the importance of confidentiality and acting with discretion and within the boundaries of one\'s role.' , videoLink: 'https://www.youtube.com/embed/1Evwgu369Jw' },
    { week: 11, term: 1, title: 'Empathy vs. Sympathy', focus: 'MHFA', theme: 'MHFA', objectives: ['Understand the difference between empathy (feeling with) and sympathy (feeling for).', 'Recognise how well-meant "fixing" or "rescuing" can unintentionally minimise someone\'s feelings.', 'Practise responses that build connection rather than close it down.'], activities: [createDebrief(), {name: 'Video and Discussion', desc: 'Watch Brené Brown\'s short animated video on Empathy vs. Sympathy. Discuss the key phrase "Empathy fuels connection, sympathy drives disconnection."'}, {name: '"At Least..." Jar', desc: 'Create a virtual or real "jar" where people write down unhelpful "at least..." statements they have heard, highlighting how sympathy can minimise feelings.'}, {name: 'Empathetic Response Practice', desc: 'In pairs, one person shares a small frustration while the other practices purely empathetic responses (e.g., "That sounds so hard," "I can hear how frustrating that is").'}, {name: 'Connect, Don\'t Fix', desc: 'Discuss the urge to jump in and solve, and how simply staying alongside someone is often more helpful. Link to the golden thread from Week 9: holding the moment with care is itself the gold.'}], resources: 'Laptop/projector for video.', notes: 'A key concept for preventing burnout, placed early so it underpins every supportive conversation that follows. Empathy is about connection, not taking on the other person\'s feelings. (We will revisit "rescuing" later in Term 2 when we meet the Drama Triangle.)' , videoLink: 'https://www.youtube.com/embed/qUcC71-W9Os' },
    { week: 12, term: 1, title: 'Signposting & Support', focus: 'MHFA', theme: 'MHFA', objectives: ['Understand the importance of professional boundaries in a helping role.', 'Identify appropriate internal and external sources of support.', 'Practice how to gently introduce the idea of seeking professional help.'], activities: [createDebrief(), {name: '"Warm Handovers" Discussion', desc: 'Discuss the difference between just giving a number and offering a "warm handover" (e.g., "Would you like me to sit with you while you look up that number?").'}, {name: 'Resource Scavenger Hunt', desc: 'In teams, groups have 5 minutes to find the contact information for the school\'s EAP, a local mental health charity, and the NHS mental health crisis line.'}, {name: 'Signposting Scripting', desc: 'Individually, participants write and then share useful phrases for signposting that feel natural to them.'}, {name: 'Boundary Role-Play', desc: 'Role-play a scenario where a colleague is asking for more support than you can give, and practice referring them to a more appropriate service kindly.'}], resources: 'Flip chart, pens, list of local/organisational support services.', notes: 'Reassure the group that their role is to open the door to help, not to force someone through it.' , videoLink: 'https://www.youtube.com/embed/FXnPeKLrD-w' },
    { week: 13, term: 1, title: 'Term 1 Review', focus: 'Consolidation', theme: 'Integration', objectives: ['Consolidate the key concepts from Term 1.', 'Reflect on personal learning and growth.', 'Set intentions for the holiday break.'], activities: [createDebrief(), {name: 'Key Takeaway Circle', desc: 'Each person shares one key concept or skill from the term that has been most impactful for them.'}, {name: '"Start, Stop, Continue" Reflection', desc: 'Participants reflect on one wellbeing habit they want to Start, one unhelpful habit to Stop, and one positive habit to Continue over the break.'}, {name: 'Appreciation Station', desc: 'A final round of appreciation where each member thanks the group or an individual for their support during the term.'}, {name: 'One-Word Intention', desc: 'Each person shares one word that represents their intention for the holiday break (e.g., "Rest," "Connection," "Fun").'}], resources: 'Paper, pens.', notes: 'End the term on a positive and encouraging note. Acknowledge the hard work and courage shown by the participants. Return briefly to the Kintsugi image from Week 9 — invite the group to notice the gold they have already worked into their own cracks this term.' , videoLink: 'https://www.youtube.com/embed/JfdoJxPjp1k' },
    { week: 14, term: 2, title: 'Protecting Your Joy', focus: 'MHFA', theme: 'MHFA', objectives: ['Recognise that guarding the things that restore you is a core part of staying well in a high-demand role — not a luxury.', 'Identify your own genuine sources of joy and the activities that truly refill your tank.', 'Build practical, kind boundaries that protect your free time and energy away from work.'], activities: [createDebrief(), {name: 'Your Joy Inventory', desc: 'Each person quietly lists the small and large things that reliably bring them joy or restore them — then marks how often each actually happens in a typical month.'}, {name: 'Energy Givers & Takers', desc: 'Sort recent commitments into what gives energy versus what drains it, and notice where free time is quietly leaking into work.'}, {name: 'Protecting the Edges', desc: 'Practise kind, firm scripts for guarding personal time — e.g. "I do not check emails after 6pm," or "Weekends are for my family." Share one you will actually use.'}, {name: 'One Joy, Protected', desc: 'Each person commits to one source of joy they will defend this fortnight, and names the boundary that will keep it safe. Link to the golden thread from Week 9: you can only keep mending others if you protect your own gold.'}], resources: 'Paper, pens; optional printed "energy givers/takers" sheet.', notes: 'High emotional labour makes joy and rest essential maintenance, not indulgence — say this plainly. This complements the later "Proactive Self-Care" session (Week 30): here the focus is specifically on joy and protecting free time. Encourage tiny, defendable boundaries over grand intentions.' , videoLink: 'https://www.youtube.com/embed/c1Ndym-IsQg' },
    { week: 15, term: 2, title: 'The Window of Tolerance', focus: 'Regulation', theme: 'Regulation', objectives: ['Understand the "Window of Tolerance" — the zone where we feel calm, present and able to think clearly.', 'Recognise the signs of tipping into hyper-arousal (fight/flight) or hypo-arousal (shutdown), in ourselves and others.', 'Build practical ways to widen the window and return to it under pressure.'], activities: [createDebrief(), {name: 'Mapping the Window', desc: 'On paper, each person sketches their own window: what hyper-arousal looks like for them at the top, hypo-arousal at the bottom, and the steady zone in between. Name your personal early-warning signs.'}, {name: 'What Narrows It', desc: 'Discuss the things that shrink the window on a hard day — tiredness, hunger, back-to-back demands — and notice how a narrow window makes us quicker to react.'}, {name: 'Widening Practices', desc: 'Share and try quick, repeatable ways to come back to the window: grounding through the senses, a longer exhale, a brief movement break. Each person picks one that works for them.'}, {name: 'Co-Regulation', desc: 'Discuss how a regulated adult helps a dysregulated young person back into their window — and how the same is true for colleagues. We borrow each other\'s calm.'}], resources: 'Paper, pens; optional printed Window of Tolerance diagram.', notes: 'A natural Term 2 extension of the Week 1 regulation work. Keep it normalising: everyone\'s window narrows under load — the skill is noticing early and coming back, not never leaving.' , videoLink: 'https://www.youtube.com/embed/F0WYFXxhPGY' },
    { week: 16, term: 2, title: 'Active Listening', focus: 'Dynamics', theme: 'TA', objectives: ['Understand listening as a relational act — and one of the most powerful positive "strokes" we can give.', 'Practise listening from the calm, curious "Adult" ego state rather than jumping to Parent (advice) or Child (defence).', 'Learn to hear the ego state and feeling beneath the words, not just the content.'], activities: [createDebrief(), {name: 'Listening as a Stroke', desc: 'Discuss how full attention is itself recognition — a stroke. Recall a time someone really listened to you, and what it gave you.'}, {name: 'Adult-State Listening Dyads', desc: 'In pairs, Person A shares a minor work frustration; Person B listens only from the Adult — no fixing, no reassuring-away, just curious attention and reflecting back. Swap and debrief.'}, {name: 'Hearing the Ego State', desc: 'Listen to a short scenario and identify which ego state the speaker is in, and what feeling sits under the words. Practise responding to the feeling, not just the facts.'}, {name: 'Minimal Encouragers', desc: 'Practise the small signals — nodding, "mm," brief paraphrases — that keep someone talking and feeling heard without taking over.'}], resources: 'None required; optional ego-state reminder cards.', notes: 'Bridges the TA work with everyday helping conversations. Emphasise that listening well is a skill that protects relationships and prevents small things escalating. Listening is gold leaf — the golden thread made of attention.' , videoLink: 'https://www.youtube.com/embed/z_-rNd7h6z8' },
    { week: 17, term: 2, title: 'Ego & Presence', focus: 'Dynamics', theme: 'TA', objectives: ['Meet Eckhart Tolle\'s idea of the "ego" as the voice in the head we mistake for ourselves.', 'Connect this to TA: the observing, present "Adult" can watch the reactive ego rather than being run by it.', 'Practise a moment of presence as a way to step out of automatic reaction.'], activities: [createDebrief(), {name: 'The Voice in the Head', desc: 'Introduce Tolle\'s notion that much of our suffering comes from over-identifying with the constant stream of thinking. Watch the short video and gather first reactions.'}, {name: 'Ego Meets Ego State', desc: 'Discuss the overlap: Tolle\'s "ego" and TA\'s reactive Parent/Child states both run on autopilot, while "presence" and the "Adult" both involve stepping back and observing.'}, {name: 'The Observing Pause', desc: 'Practise a 60-second presence exercise — noticing thoughts come and go without believing every one. Notice the small gap this creates before reacting.'}, {name: 'Catching the Hook', desc: 'Recall a recent moment you got "hooked" into reactivity. Where could a breath of presence have let the Adult respond instead?'}], resources: 'Laptop/projector for the video; quiet space for the presence exercise.', notes: 'Keep it practical and non-dogmatic — this is a workplace wellbeing lens, not a belief system. The takeaway: a small pause of awareness gives us choice. (Note: the linked Tolle video runs longer than our usual clips; you may wish to show only the opening section.)' , videoLink: 'https://www.youtube.com/embed/M1dlEocp_Yo' },
    { week: 18, term: 2, title: 'Calming the Busy Mind', focus: 'Regulation', theme: 'Regulation', objectives: ['Recognise the "busy mind" — racing, looping thoughts — as a normal stress response, not a personal failing.', 'Carrying on from the presence work, learn simple attention practices that settle mental noise.', 'Build a short, repeatable routine for steadying the mind in a demanding day.'], activities: [createDebrief(), {name: 'Naming the Noise', desc: 'Each person notices what their busy mind sounds like under pressure — to-do lists, replays, worries — and shares one common loop without judgment.'}, {name: 'Anchor Attention', desc: 'Practise gently returning attention to a single anchor (the breath, sounds in the room, feet on the floor) each time the mind wanders. The returning is the skill.'}, {name: 'A One-Minute Reset', desc: 'Build a personal 60-second reset to use between tasks or before a tricky moment, so the mind starts fresh rather than carrying the last thing over.'}, {name: 'Permission to Pause', desc: 'Discuss the workplace belief that we must always be "doing," and give each other permission to take brief, legitimate pauses as part of doing the job well.'}], resources: 'Quiet space; optional timer for the practices.', notes: 'A regulation session that lands the presence idea from Week 17 in the body. Keep it light and practical — the aim is a steadier mind, not an empty one.' , videoLink: 'https://www.youtube.com/embed/qxyVCjp48S4' },
    { week: 19, term: 2, title: 'Debrief: Ego States', focus: 'Application', theme: 'Integration', objectives: ['To embed the learning from the TA deep dive.', 'To practice using TA as a live debriefing tool for relational dynamics.'], activities: [createDebrief(), {name: 'Live Ego State Analysis', desc: 'Analyse the deconstructed scenario by mapping the ego states of the participants in real-time on a whiteboard.'}, {name: 'Identifying the "Hook"', desc: 'Discuss what was said or done that "hooked" a Parent or Child response, escalating the situation.'}, {name: 'Role-Playing the "Adult"', desc: 'Volunteers role-play the scenario again, this time consciously trying to maintain an "Adult" ego state throughout.'}, {name: 'Reflection', desc: 'A group reflection on how challenging it is to stay in "Adult" when feeling stressed or threatened.'}], resources: 'Whiteboard, pens.', notes: 'Focus on curiosity and exploration, not on getting it "right." Normalise the difficulty of staying in Adult. Recap: this revisits the video from Week 4 (Transactional Analysis Intro) as a deliberate refresher of the core TA ideas.' , videoLink: 'https://www.youtube.com/embed/oPJtRDul0do' },
    { week: 20, term: 2, title: 'Growth Mindset Deepdive', focus: 'Integration', theme: 'Integration', objectives: ['Understand the difference between a fixed and a growth mindset, and how the language of "yet" reframes difficulty.', 'Explore how setbacks and mistakes become the raw material for growth \u2014 the Kintsugi golden thread, where cracks are filled with gold.', 'Take unhurried time to apply a growth mindset to a real challenge in your own practice.'], activities: [createDebrief(), {name: 'Fixed vs. Growth', desc: 'Introduce the two mindsets with everyday examples. The group sorts a set of common staffroom phrases into "fixed" or "growth" and rewrites the fixed ones.'}, {name: 'The Power of "Yet"', desc: 'Practise adding "yet" to fixed statements ("I cannot manage that class" becomes "...yet"). Notice how it changes the feeling and opens a path forward.'}, {name: 'Setbacks into Gold', desc: 'Connecting back to Week 9: each person revisits a recent setback and explores, without rushing, what it is teaching them \u2014 the gold beginning to fill the crack.'}, {name: 'Open Exploration', desc: 'Deliberately unstructured time to discuss the theme as a group \u2014 where fixed mindsets show up in the work, with students, and in ourselves, and how a growth stance might shift them.'}], resources: 'Whiteboard, pens; optional fixed/growth phrase cards.', notes: 'A reflective deepdive rather than a packed session \u2014 protect the open exploration time. The linked video is repeated from Week 13 as a deliberate recap to anchor the growth-mindset theme.' , videoLink: 'https://www.youtube.com/embed/JfdoJxPjp1k' },
    { week: 21, term: 2, title: 'The Practice of Gratitude', focus: 'Resilience', theme: 'MHFA', objectives: ['Understand why gratitude is one of the most reliable, evidence-based boosts to wellbeing and resilience.', 'Build the muscle of noticing what is good, especially on demanding days when it is hardest to see.', 'Practise expressing genuine appreciation to others \u2014 gratitude as a stroke that strengthens the team.'], activities: [createDebrief(), {name: 'Why Gratitude Works', desc: 'Watch the short video and discuss how deliberately noticing the good shifts attention away from the brain\u2019s negativity bias \u2014 not toxic positivity, but a fuller, truer picture.'}, {name: 'Three Good Things', desc: 'Each person notes three things that went well recently, however small, and why. Introduce this as a simple practice to repeat at the end of a working day.'}, {name: 'Gratitude as a Stroke', desc: 'Building on the recognition work: each person offers one specific, heartfelt thank-you to a colleague \u2014 naming what they did and the difference it made.'}, {name: 'A Gratitude Habit', desc: 'Each person chooses a tiny, anchored gratitude habit for the fortnight (e.g. one thing you are grateful for on the drive home) and shares it for accountability.'}], resources: 'Laptop/projector for the video; paper and pens for notes.', notes: 'Keep it authentic, not forced \u2014 gratitude sits alongside difficulty, it does not deny it. A natural follow-on from the recognition and \u201cstrokes\u201d work, and a genuine protective factor against burnout.' },
    { week: 22, term: 2, title: 'My Ego', focus: 'Dynamics', theme: 'TA', objectives: ['Turn the lens inward: get honest about your own habitual ego states and where you spend most of your time.', 'Notice which state you default to under stress — the reactive Parent or Child that gets “hooked” when you are tired or pushed.', 'Strengthen the observing, present “Adult” so you can choose your response rather than be run by the ego.'], activities: [createDebrief(), {name: 'My Ego State Map', desc: 'Each person privately maps their own Parent, Adult and Child — typical phrases, postures and triggers for each — and marks the one they live in most at work.'}, {name: 'My Default Under Stress', desc: 'Reflect honestly on where you go when stretched: do you slip into controlling Parent, pleasing Child, or rebellious Child? Name it without judgment.'}, {name: 'The Observing Pause', desc: 'Building on Ego & Presence (Week 17): practise catching your own ego in the moment, taking a breath, and stepping back into the Adult before responding.'}, {name: 'One Honest Commitment', desc: 'Each person names one situation this fortnight where they will try to notice their ego rising and choose the Adult instead.'}], resources: 'Paper, pens; optional ego-state reminder cards.', notes: 'This is personal and can feel exposing — keep it confidential and self-directed, with no pressure to share. The goal is honest self-awareness, not self-criticism.' },
    { week: 23, term: 2, title: 'Critical Incident Deep Dive', focus: 'Application', theme: 'Integration', objectives: ['Work through a real, significant event from the academic year so far, using the full toolkit built across the programme.', 'Practise a structured, blame-free way of understanding what happened and why — body, relationships and reasoning together.', 'Draw out concrete learning and a kinder, clearer plan for if something similar happens again.'], activities: [createDebrief(), {name: 'Choosing the Incident', desc: 'As a group, agree on one genuine incident from the year to deconstruct — anonymised and handled with care. Set ground rules for safety and confidentiality before starting.'}, {name: 'Regulate → Relate → Reason', desc: 'Walk the event through the Neurosequential lens: where was each person on the regulation ladder, what state were relationships in, and when did clear reasoning come back online?'}, {name: 'The TA Layer', desc: 'Map the ego states and transactions at play — where things got “hooked”, and where an Adult-to-Adult move could have shifted the outcome.'}, {name: 'Gold from the Crack', desc: 'Close by naming the golden thread: what the team did well, what held people together, and the specific learning to carry forward (link to Week 9 Kintsugi).'}], resources: 'Whiteboard, pens; the programme\'s frameworks to hand; agreed confidentiality ground rules.', notes: 'Choose the incident sensitively and keep it safe — this is a learning deconstruction, not a place to assign blame or re-traumatise. If the event was serious, ensure proper debriefing and support channels are also in place alongside this reflective session.' },
    { week: 24, term: 2, title: 'Checking In With Others', focus: 'MHFA', theme: 'MHFA', objectives: ['Learn how to approach someone you are concerned about.', 'Practice using open-ended, non-judgmental questions.', 'Understand the power of active listening.'], activities: [createDebrief(), {name: 'Active Listening Dyads', desc: 'In pairs, Person A talks for 3 minutes about a minor stressor. Person B can only listen, nod, and use minimal encouragers. Swap roles and debrief.'}, {name: 'Open vs. Closed Questions', desc: 'The group converts a list of closed questions (e.g., "Are you okay?") into more effective open questions (e.g., "How have things been for you lately?").'}, {name: 'ALGEE Model Introduction', desc: 'Introduce the ALGEE model (Approach, Listen, Give support, Encourage professional help, Encourage other supports), focusing on A & L.'}, {name: 'Role-Play Trios', desc: 'In trios (Approacher, Receiver, Observer), practice starting a supportive conversation. The observer gives feedback on body language and tone.'}], resources: 'ALGEE model handout.', notes: 'Acknowledge that these conversations can feel awkward. The goal is to practice and build confidence in a safe setting.' , videoLink: 'https://www.youtube.com/embed/cEqZthCaMpo' },
    { week: 25, term: 2, title: 'Boundaries in Helping', focus: 'MHFA', theme: 'MHFA', objectives: ['Revisit the importance of boundaries in maintaining well-being.', 'Identify personal boundaries in helping colleagues.', 'Practice communicating boundaries clearly and kindly.'], activities: [createDebrief(), {name: 'Types of Boundaries', desc: 'Discuss different types of boundaries: physical, emotional, time, and energy. Participants reflect on which are hardest for them to maintain.'}, {name: '"Yes/No" Reflection', desc: 'Participants reflect on a time they said "yes" when they wanted to say "no," and explore the consequences for their own wellbeing.'}, {name: 'Boundary Scripting', desc: 'Work in small groups to create and practice kind but firm scripts for common boundary-pushing scenarios at work.'}, {name: 'Permission to Have Boundaries', desc: 'A closing round where each person completes the sentence: "I give myself permission to..." (e.g., "...not answer emails after 6 pm").'}], resources: 'None.', notes: 'Link this back to the Assertive "No" from Term 1. It\'s the same skill in a different context.' },
    { week: 26, term: 2, title: 'Term 2 Review', focus: 'Consolidation', theme: 'Integration', objectives: ['Consolidate the key TA concepts from Term 2.', 'Reflect on how this understanding has changed their perception of workplace dynamics.'], activities: [createDebrief(), {name: 'TA in Action Skits', desc: 'In small groups, participants choose one TA concept (e.g., Games, Drivers) and create a short, 1-minute skit to demonstrate it to the group.'}, {name: 'Most Valuable Concept', desc: 'Each person shares which TA concept from this term has been the most illuminating or useful for them personally.'}, {name: '"I Will Try..." Statements', desc: 'Participants share one thing they will try to do differently in their interactions based on their learning this term.'}, {name: 'Team Appreciation', desc: 'A final round of appreciation for the group\'s willingness to be vulnerable and learn together.'}], resources: 'None.', notes: 'Keep this session light and engaging. The skits are a great way to check for understanding in a fun format.' },
    { week: 27, term: 3, title: 'Brain & Communication', focus: 'Integration', theme: 'Integration', objectives: ['To explicitly link the Neurosequential model and TA.', 'Understand how a dysregulated state (brainstem/limbic) leads to Child/Parent ego states and dysfunctional communication.'], activities: [createDebrief(), {name: 'The Integrated Model Drawing', desc: 'On a whiteboard, draw the "Regulate-Relate-Reason" triangle next to the P-A-C ego states. Explicitly link Regulate->Child, Relate->Parent, Reason->Adult.'}, {name: 'Scenario Mapping', desc: 'Analyse a scenario by asking: "Where was this person on the Neurosequential triangle? Therefore, which ego state were they likely in?"'}, {name: '"Connect Before Correct" in TA', desc: 'Discuss how "connecting" is a relational (Parent/Child) act, and "correcting" is a reasoning (Adult) act. You can\'t do the second without the first.'}, {name: 'Personal Reflection', desc: 'Journal prompt: "When I am dysregulated, which ego state (Parent or Child) do I tend to default to?"'}], resources: 'Flip chart, pens.', notes: 'This is the "aha!" moment for many. Spend time making the visual link clear and repeating the core message. Tie it back to the Kintsugi golden thread from Week 9: regulation and relationship are the gold that rejoins the pieces.' , videoLink: 'https://www.youtube.com/embed/qxyVCjp48S4' },
    { week: 28, term: 3, title: 'Stress & Scripts', focus: 'Integration', theme: 'Integration', objectives: ['To link TA Drivers to the physiological stress response.', 'Understand how our script-driven behaviours can keep us in a state of chronic stress.'], activities: [createDebrief(), {name: 'Driver Body Scan', desc: 'Participants identify their main Driver, then do a body scan noticing where that Driver "lives" in their body (e.g., tight shoulders for "Be Strong").'}, {name: 'The Cost of Scripts', desc: 'Discuss the long-term physical and emotional cost of constantly running a script Driver (e.g., exhaustion from "Try Hard").'}, {name: 'Script-Interrupting Strategies', desc: 'Brainstorm specific regulation strategies that directly counter each Driver (e.g., for "Hurry Up," the strategy is to deliberately slow down your breathing and movements).'}, {name: 'Applying "Allowers"', desc: 'Practice saying the "Allower" for your primary Driver out loud as a form of self-permission.'}], resources: 'Handout on Drivers from Term 2.', notes: 'This connects the abstract idea of "scripts" to the felt sense in the body, making it more tangible.' },
    { week: 29, term: 3, title: 'Proactive Self-Care', focus: 'Resilience', theme: 'Regulation', objectives: ['Distinguish between reactive coping and proactive self-care.', 'Identify activities that are genuinely restorative.', 'Create a plan to schedule these activities.'], activities: [createDebrief(), {name: 'Reactive vs. Proactive', desc: 'On a whiteboard, create two columns: "Reactive Coping" (e.g., wine, complaining) and "Proactive Care" (e.g., exercise, hobbies). Discuss the difference in outcomes.'}, {name: 'The Wellness Wheel', desc: 'Participants use the Wellness Wheel to assess different life areas, identifying one area that needs more proactive attention.'}, {name: 'Energy Givers vs. Takers', desc: 'Participants list activities that drain their energy and activities that replenish it, and reflect on the balance between the two in their week.'}, {name: 'Scheduling Self-Care', desc: 'Participants take out their actual diaries/phones and schedule one non-negotiable 30-minute proactive care activity for the coming week.'}], resources: '"Wellness Wheel" worksheet.', notes: 'The key is scheduling. If it\'s not in the diary, it often doesn\'t happen. Emphasise that this is not selfish, it is essential maintenance.' },
    { week: 30, term: 3, title: 'Managing Compassion Fatigue', focus: 'Resilience', theme: 'MHFA', objectives: ['Define compassion fatigue, secondary trauma, and burnout.', 'Recognise personal warning signs.', 'Develop strategies to protect personal energy.'], activities: [createDebrief(), {name: 'Defining the Terms', desc: 'Clearly define and differentiate Compassion Fatigue, Secondary Trauma, and Burnout using clear, simple language.'}, {name: 'Personal Warning Signs Checklist', desc: 'Participants use a confidential checklist to identify their own early warning signs of fatigue or burnout.'}, {name: '"Decontamination" Rituals', desc: 'Brainstorm a list of "decontamination" rituals to create a boundary between work and home (e.g., changing clothes, listening to music on the commute).'}, {name: 'Professional Detachment Practice', desc: 'Discuss the skill of professional detachment: caring deeply about the work without carrying the emotional weight of every outcome.'}], resources: 'Handout with definitions, self-assessment checklist.', notes: 'This can be a heavy topic. Handle with care and normalise the experience. It\'s a normal consequence of the work, not a personal failing.' , videoLink: 'https://www.youtube.com/embed/c1Ndym-IsQg' },
    { week: 31, term: 3, title: 'Building a Peer Support Culture', focus: 'Resilience', theme: 'Integration', objectives: ['To synthesise the learning to create a team-level plan.', 'To agree on team norms for giving and receiving support.', 'To commit to using the shared language of TA and MHFA.'], activities: [createDebrief(), {name: '"What Does Safe Look Like?"', desc: 'A group discussion on what a psychologically safe team looks, sounds, and feels like.'}, {name: 'Team Charter Creation', desc: 'As a group, create a simple "Team Charter" with 3-5 agreed-upon norms for how to support each other (e.g., "We use Adult-to-Adult communication for feedback").'}, {name: 'Collective Care Commitments', desc: 'Each person makes one specific commitment to the charter and the team\'s collective wellbeing.'}, {name: 'Modelling Vulnerability', desc: 'The practitioner models vulnerability by sharing a small, appropriate example of when they needed support, and how they asked for it.'}], resources: 'Flip chart, pens.', notes: 'This session is about ownership. Your role is to facilitate their creation of the charter, not to write it for them. Name the team itself as a shared golden thread — many hands holding and rejoining the pieces together.' },
    { week: 32, term: 3, title: 'Debrief: Bringing It Together', focus: 'Application', theme: 'Integration', objectives: ['To practice a full, integrated debrief of a situation.', 'To build confidence in using the entire framework.'], activities: [createDebrief(), {name: 'The Full-Spectrum Debrief', desc: 'Guide the group to deconstruct a scenario by moving through the full model: Regulation (body) -> TA (thoughts/interactions) -> Resilience (strategies).'}, {name: 'Connecting the Dots', desc: 'Explicitly ask "How did the lack of regulation lead to that crossed transaction?" to reinforce the integrated model.'}, {name: 'Peer-Led Analysis', desc: 'Encourage the group to lead the analysis themselves, with the practitioner acting only as a guide to keep them on track.'}, {name: 'Identifying the "Lever"', desc: 'After the analysis, ask "What was the single most powerful point of intervention where a different choice could have changed everything?"'}], resources: 'All previous handouts for reference.', notes: 'This is the culmination of the programme\'s skills. Trust the group to use the knowledge they have built.' },
    { week: 33, term: 3, title: 'Debrief: Strengths & Resilience', focus: 'Application', theme: 'Regulation', objectives: ['To practice a full, integrated debrief of a situation.', 'To build confidence in using the entire framework.'], activities: [createDebrief(), {name: 'Focus on Strengths', desc: 'In the deconstructed scenario, the primary focus is on identifying the resilience and strengths the person showed, even in a tough situation.'}, {name: 'Self-Care Plan Review', desc: 'The group discusses what proactive self-care strategies could have supported the person before the event, and what reactive strategies helped after.'}, {name: 'Boundary Analysis', desc: 'Analyse the role of boundaries in the scenario. Was a boundary crossed? Was one needed? How could it have been communicated?'}, {name: 'Collective Care in Action', desc: 'Discuss how the team, using the Team Charter, could have supported the individual involved.'}], resources: 'All previous handouts and Team Charter.', notes: 'This debrief is less about analysis and more about reinforcing the proactive, protective strategies learned.' , videoLink: 'https://www.youtube.com/embed/F0WYFXxhPGY' },
    { week: 34, term: 3, title: 'Professional Goals', focus: 'Planning', theme: 'TA', objectives: ['To use the "Adult" ego state to set realistic, value-driven professional goals for the next academic year.'], activities: [createDebrief(), {name: 'Values Clarification', desc: 'Participants choose their top 3-5 professional values from a list (e.g., creativity, collaboration, efficiency).'}, {name: 'Goal Brainstorming', desc: 'Based on their values, participants brainstorm potential professional development goals for the next year.'}, {name: 'SMART Goal Setting', desc: 'Guide participants to turn one brainstormed idea into a SMART goal (Specific, Measurable, Achievable, Relevant, Time-bound).'}, {name: 'Accountability Partners', desc: 'In pairs, participants share their SMART goal to create mutual support and accountability.'}], resources: 'Paper, pens, SMART goal handout, values list.', notes: 'Encourage goals that are about process (e.g., "I will practice pausing before reacting in meetings") as well as outcomes.' },
    { week: 35, term: 3, title: 'Personal Wellness Plan', focus: 'Planning', theme: 'Regulation', objectives: ['Creating a concrete plan for maintaining well-being over the summer break and into the next year.'], activities: [createDebrief(), {name: 'The Wellness Plan', desc: 'Participants create a simple wellness plan for the summer break, with headings like: Rest, Connection, Fun, and Growth, listing activities for each.'}, {name: 'Anticipating Barriers', desc: 'For their plan, participants identify potential barriers (e.g., family commitments) and brainstorm one strategy to overcome them.'}, {name: 'Scheduling "Anchor Points"', desc: 'Participants schedule 3-4 key wellness activities into their calendar for the break as "anchor points" for their wellbeing.'}, {name: 'Sharing the Joy', desc: 'Each person shares one thing from their wellness plan that they are most looking forward to.'}], resources: 'Wellness Plan worksheet.', notes: 'This helps bridge the gap between term-time and holidays, preventing the "crash" that can often happen.' },
    { week: 36, term: 3, title: 'Confidence in Supporting Others', focus: 'Consolidation', theme: 'MHFA', objectives: ['A final review of the MHFA principles and scenarios to build confidence in applying them when needed.'], activities: [createDebrief(), {name: 'ALGEE Pop Quiz', desc: 'A fun, low-stakes pop quiz to remind everyone of the steps in the ALGEE model.'}, {name: 'Scenario Round Robin', desc: 'In a circle, read a scenario. The first person says how they would "Approach," the next how they would "Listen," and so on around the circle.'}, {name: 'Confidence Scale', desc: 'On a scale of 1-10, participants anonymously write down their confidence in using MHFA skills. Discuss any common fears or barriers.'}, {name: 'Revisiting Boundaries', desc: 'A final discussion reinforcing the limits of the MHFA role and the critical importance of self-care and signposting.'}], resources: 'ALGEE handout, written scenarios.', notes: 'Focus on "good enough" responses, not perfect ones. The goal is to build the confidence to act, not to be an expert.' , videoLink: 'https://www.youtube.com/embed/cEqZthCaMpo' },
    { week: 37, term: 3, title: 'Letter to My Future Self', focus: 'Consolidation', theme: 'Integration', objectives: ['Write a letter to yourself to be opened at the start of the next academic year, capturing key learnings and future hopes.'], activities: [createDebrief(), {name: 'Guided Reflection', desc: 'Practitioner leads a short, guided reflection on the year, prompting memories of challenges, growth, and connection.'}, {name: 'Letter Writing', desc: 'Participants are given quiet time to write a letter to themselves, using prompts like "What I learned...", "I am proud of...", "My hope is...".'}, {name: 'Sealing the Letter', desc: 'Participants seal their letters in envelopes, which the practitioner can offer to keep safe until the start of the next academic year.'}, {name: 'Sharing a Hope', desc: 'As a closing circle, each person shares one hope they have for their future self.'}], resources: 'Nice paper, pens, envelopes.', notes: 'Create a quiet, reflective atmosphere for this session. It can be very powerful and is a testament to the journey taken.' },
    { week: 38, term: 3, title: 'Debrief: Self-Worth', focus: 'Application', theme: 'TA', objectives: ['To embed the learning from week 5.', 'To practice using "Strokes" as a live debriefing tool.', 'To build psychological safety within the group.'], activities: [createDebrief(), {name: 'Finding the Positive', desc: 'Even in the difficult deconstructed scenario, the group works to find one thing the person handled well or one positive intention they had.'}, {name: 'Self-Stroke Practice', desc: 'The person who shared the scenario is guided to formulate a positive "I..." statement about their own strength or resilience in the situation.'}, {name: 'The "Stroke" Go-Around', desc: 'Each member of the group offers one piece of positive, unconditional recognition (a "stroke") to the person who shared.'}, {name: 'Goal-Setting Link', desc: 'Connect the learning from the debrief to setting a small, positive goal for the week ahead.'}], resources: 'None.', notes: 'This session is about actively countering negativity bias and building a culture of positive recognition.' },
    { week: 39, term: 3, title: 'Celebration & Affirmation', focus: 'Consolidation', theme: 'Integration', objectives: ['A final session dedicated entirely to positive peer affirmations. Acknowledging individual and collective growth and success throughout the year.'], activities: [createDebrief(), {name: 'Affirmation Circle', desc: 'Each person has a piece of paper with their name on it. The papers are passed around the circle, and every person writes one positive affirmation or "stroke" on each person\'s sheet.'}, {name: 'Reading and Receiving', desc: 'The papers are returned to their owners. Allow quiet time for everyone to read their affirmations and absorb the positive recognition.'}, {name: 'Team Successes', desc: 'As a group, brainstorm and list all the collective successes and achievements of the team over the past year.'}, {name: 'Final Toast', desc: 'A final closing toast (with non-alcoholic drinks) to the team, their hard work, and their continued development.'}], resources: 'Paper, pens, perhaps some light refreshments.', notes: 'This is a purely positive session. Your role is to hold the space and participate fully. End the year on a high note of connection and mutual respect. Close by returning to Week 9: each person has been a golden thread this year, and the team is more beautiful for the breaks it has survived together.' , videoLink: 'https://www.youtube.com/embed/c1Ndym-IsQg' },
];